    <style>
        html { scroll-behavior: smooth; }
        
        /* Animasi Fade In Up */
        @keyframes fadeInUp {
            from {
                opacity: 0;
                transform: translateY(30px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }
        
        /* Animasi Fade In Left */
        @keyframes fadeInLeft {
            from {
                opacity: 0;
                transform: translateX(-30px);
            }
            to {
                opacity: 1;
                transform: translateX(0);
            }
        }
        
        /* Animasi Fade In Right */
        @keyframes fadeInRight {
            from {
                opacity: 0;
                transform: translateX(30px);
            }
            to {
                opacity: 1;
                transform: translateX(0);
            }
        }
        
        /* Animasi Bounce */
        @keyframes bounce {
            0%, 20%, 50%, 80%, 100% {
                transform: translateY(0);
            }
            40% {
                transform: translateY(-10px);
            }
            60% {
                transform: translateY(-5px);
            }
        }
        
        /* Animasi Pulse */
        @keyframes pulse {
            0% {
                transform: scale(1);
            }
            50% {
                transform: scale(1.05);
            }
            100% {
                transform: scale(1);
            }
        }
        
        /* Animasi Slide In */
        @keyframes slideIn {
            from {
                opacity: 0;
                transform: translateY(100px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }
                opacity: 0;
            }
        }

        .animate-slide-in {
            animation: slideIn 0.3s ease-out;
        }

        .animate-slide-out {
            animation: slideOut 0.3s ease-out;
        }

        .modal-backdrop {
            backdrop-filter: blur(4px);
        }

        .notification-enter {
            animation: slideIn 0.3s ease-out;
        }

        .notification-exit {
            animation: slideOut 0.3s ease-out;
        }
        .carousel-track { display: flex; gap: 2rem; transition: transform 0.5s ease-in-out; }
        .carousel-item { min-width: 320px; flex-shrink: 0; }
        .carousel-btn {
            position: absolute; top: 50%; transform: translateY(-50%);
            background-color: rgba(139, 0, 0, 0.8); color: white; border: none;
            width: 50px; height: 50px; border-radius: 50%; cursor: pointer;
            font-size: 24px; display: flex; align-items: center; justify-content: center;
            z-index: 10; transition: all 0.3s ease;
        }
        .carousel-btn:hover { background-color: rgba(139, 0, 0, 1); transform: translateY(-50%) scale(1.1); }
        .carousel-btn.prev { left: 10px; }
        .carousel-btn.next { right: 10px; }
        .contact-icon { transition: transform 0.3s ease; }
        .contact-icon:hover { transform: scale(1.1) rotate(5deg); }
        .fade-up {
            opacity: 1;
            transform: translateY(0);
            transition: opacity 0.6s ease, transform 0.6s ease;
        }
        .js .fade-up {
            opacity: 0;
            transform: translateY(30px);
        }
        .fade-up.visible {
            opacity: 1;
            transform: translateY(0);
        }
        .halal-intro {
            opacity: 1;
            transform: translateY(0) scale(1);
            transition: opacity 1.2s cubic-bezier(0.16, 1, 0.3, 1), transform 1.2s cubic-bezier(0.16, 1, 0.3, 1);
            will-change: transform, opacity;
        }
        .js .halal-intro {
            opacity: 0;
            transform: translateY(80px) scale(0.965);
        }
        .halal-intro.visible {
            opacity: 1;
            transform: translateY(0) scale(1);
        }
        .halal-logo,
        .halal-desc {
            opacity: 0;
            transform: translateY(34px) scale(0.985);
            transition: opacity 1s cubic-bezier(0.16, 1, 0.3, 1), transform 1s cubic-bezier(0.16, 1, 0.3, 1);
            will-change: transform, opacity;
        }
        .halal-intro.visible .halal-logo,
        .halal-intro.visible .halal-desc {
            opacity: 1;
            transform: translateY(0) scale(1);
        }
        .halal-intro.visible .halal-logo {
            transition-delay: 0.12s;
        }
        .halal-intro.visible .halal-desc {
            transition-delay: 0.34s;
        }
        .rekomendasi-slider {
            position: relative;
            margin: 0 auto;
            padding: 1rem 0;
            width: 100%;
        }

        .rekomendasi-viewport {
            overflow: hidden;
            margin: 0 auto;
            border-radius: 1.5rem;
            padding: 0.5rem 0; /* Memberi ruang untuk efek shadow card saat hover */
            width: max-content;
            max-width: 100%;
        }

        @media (max-width: 639px) {
            .rekomendasi-viewport { max-width: 256px; } /* 1 card */
        }
        @media (min-width: 640px) and (max-width: 1023px) {
            .rekomendasi-viewport { max-width: 536px; } /* 2 cards */
        }
        @media (min-width: 1024px) {
            .rekomendasi-viewport { max-width: 872px; } /* 3 cards */
        }

        .rekomendasi-track {
            display: flex;
            align-items: stretch;
            gap: 1rem;
            width: max-content;
            transition: none;
            will-change: transform;
            padding: 0 0 1rem 0;
        }

        .rekomendasi-item {
            flex: 0 0 240px;
            padding: 0;
            display: flex;
        }
        
        .rekomendasi-item > div {
            width: 100%;
        }

        @media (min-width: 640px) {
            .rekomendasi-item {
                flex-basis: 260px;
            }
        }

        @media (min-width: 1024px) {
            .rekomendasi-item {
                flex-basis: 280px;
            }
        }

        .influencer-card {
            border-radius: 16px;
            transition: transform 0.35s ease, box-shadow 0.35s ease;
        }

        .influencer-media {
            position: relative;
            border-radius: 16px;
            overflow: hidden;
            background: #fff;
            box-shadow: 0 10px 22px rgba(58, 42, 26, 0.14);
        }

        .influencer-media img {
            transition: transform 0.55s ease;
        }

        .influencer-media::after {
            content: '';
            position: absolute;
            left: 0;
            right: 0;
            bottom: 0;
            height: 45%;
            background: linear-gradient(to top, rgba(0, 0, 0, 0.32), rgba(0, 0, 0, 0));
            pointer-events: none;
        }

        .influencer-play {
            position: absolute;
            left: 50%;
            top: 50%;
            transform: translate(-50%, -50%);
            width: 46px;
            height: 46px;
            border-radius: 999px;
            background: rgba(255, 255, 255, 0.9);
            color: #b42318;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 0.95rem;
            box-shadow: 0 8px 16px rgba(0, 0, 0, 0.18);
            transition: transform 0.3s ease, background-color 0.3s ease, color 0.3s ease;
        }

        .influencer-badge {
            position: absolute;
            top: 12px;
            left: 12px;
            background: #b42318;
            color: #fff;
            font-size: 0.68rem;
            font-weight: 700;
            letter-spacing: 0.03em;
            padding: 0.35rem 0.65rem;
            border-radius: 999px;
            max-width: 82%;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .influencer-cta {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            gap: 0.45rem;
            background: #b42318;
            color: #fff;
            font-size: 0.72rem;
            font-weight: 700;
            letter-spacing: 0.03em;
            padding: 0.58rem 1.1rem;
            border-radius: 999px;
            transition: transform 0.25s ease, background-color 0.25s ease, box-shadow 0.25s ease;
            box-shadow: 0 8px 16px rgba(180, 35, 24, 0.28);
        }

        .influencer-cta .external-icon {
            font-size: 0.68rem;
            opacity: 0.9;
            transform: translateY(0);
            transition: transform 0.25s ease, opacity 0.25s ease;
        }

        .influencer-meta {
            margin-top: 1rem;
            display: flex;
            justify-content: center;
            flex-wrap: wrap;
            gap: 0.65rem;
        }

        .influencer-stat {
            display: inline-flex;
            align-items: center;
            gap: 0.4rem;
            background: rgba(255, 255, 255, 0.62);
            border: 1px solid rgba(122, 46, 32, 0.12);
            border-radius: 999px;
            padding: 0.38rem 0.72rem;
            font-size: 0.72rem;
            color: #5a1f18;
            font-weight: 600;
        }

        .influencer-card:hover {
            transform: translateY(-4px);
        }

        .influencer-card:hover .influencer-media {
            box-shadow: 0 16px 30px rgba(58, 42, 26, 0.2);
        }

        .influencer-card:hover .influencer-media img {
            transform: scale(1.045);
        }

        .influencer-card:hover .influencer-play {
            transform: translate(-50%, -50%) scale(1.07);
            background: #b42318;
            color: #fff;
        }

        .influencer-card:hover .influencer-cta {
            transform: translateY(-2px);
            background: #8f1e14;
            box-shadow: 0 12px 20px rgba(143, 30, 20, 0.3);
        }

        .influencer-card:hover .influencer-cta .external-icon {
            transform: translate(1px, -1px);
            opacity: 1;
        }

        @media (prefers-reduced-motion: reduce) {
            .influencer-card,
            .influencer-media,
            .influencer-media img,
            .influencer-play,
            .influencer-cta,
            .influencer-cta .external-icon {
                transition: none !important;
            }
        }

        .rekomendasi-nav {
            position: absolute;
            top: 50%;
            transform: translateY(-50%);
            width: 34px;
            height: 34px;
            border-radius: 999px;
            border: 1px solid rgba(90, 31, 24, 0.2);
            background: rgba(255, 255, 255, 0.9);
            color: #5a1f18;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: all 0.2s ease;
            z-index: 2;
        }

        .rekomendasi-nav:hover {
            background: #ffffff;
            transform: translateY(-50%) scale(1.05);
        }

        .rekomendasi-nav.prev {
            left: 0.35rem;
        }

        .rekomendasi-nav.next {
            right: 0.35rem;
        }
        
        /* Filter Button Styles */
        .filter-btn {
            transition: all 0.3s ease;
            position: relative;
            overflow: hidden;
        }
        
        .filter-btn::before {
            content: '';
            position: absolute;
            top: 0;
            left: -100%;
            width: 100%;
            height: 100%;
            background: linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent);
            transition: left 0.5s;
        }
        
        .filter-btn:hover::before {
            left: 100%;
        }
        
        .filter-btn.active {
            transform: scale(1.05);
            box-shadow: 0 4px 15px rgba(139, 0, 0, 0.3);
        }
        
        /* Loading Spinner */
        .spinner {
            border: 3px solid #f3f3f3;
            border-top: 3px solid #8B0000;
            border-radius: 50%;
            width: 40px;
            height: 40px;
            animation: spin 1s linear infinite;
            margin: 0 auto;
        }
        
        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
        
        /* Mobile Responsive Styles */
        @media (max-width: 768px) {
            .package-card {
                margin-bottom: 1.5rem;
            }
            .package-card img {
                height: 200px !important;
            }
            .package-card h4 {
                font-size: 1.5rem !important;
            }
            .package-card .price {
                font-size: 1.75rem !important;
            }
        }
        
        @media (max-width: 640px) {
            .package-card img {
                height: 180px !important;
            }
            .package-card h4 {
                font-size: 1.25rem !important;
            }
            .package-card .price {
                font-size: 1.5rem !important;
            }
            .package-card ul li {
                font-size: 0.875rem !important;
            }
        }
    /* Background Selector Dots */
        .bg-slide {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            opacity: 0;
            transition: opacity 0.8s ease-in-out;
            overflow: hidden;
        }
        
        .bg-slide.active {
            opacity: 1;
        }
        
        .bg-slide img {
            width: 100%;
            height: 100%;
            object-fit: cover;
        }
        
        /* Dot Buttons */
        .active-dot {
            background-color: rgba(255, 255, 255, 0.8) !important;
            border-color: white !important;
            transform: scale(1.2);
        }
        
        /* Hover effects for dots */
        button[id^="dot"]:hover {
            transform: scale(1.1);
            background-color: rgba(255, 255, 255, 0.6);
        }
        
        button[id^="dot"]:active {
            transform: scale(0.95);
        }
        
        /* Smooth background transition */
        #bg1, #bg2 {
            transition: opacity 0.8s ease-in-out;
        }

        .typing-title {
            display: inline-block;
            min-height: 1.2em;
        }

        .typing-caret {
            border-right: 2px solid rgba(255, 255, 255, 0.95);
            padding-right: 0.12em;
            animation: caretBlink 0.7s steps(1, end) infinite;
        }

        .hero-accent-kuah {
            position: relative;
            display: inline-block;
            padding: 0.02em 0.4em 0.06em;
            margin-left: 0.08em;
            color: #fffaf4;
            z-index: 1;
            text-shadow: 0 1px 2px rgba(0, 0, 0, 0.35);
            isolation: isolate;
        }

        .hero-accent-kuah::before {
            content: '';
            position: absolute;
            z-index: -1;
            left: -0.1em;
            right: -0.12em;
            top: 50%;
            bottom: -0.14em;
            transform: translateY(-50%) rotate(-1.5deg);
            background:
                radial-gradient(130% 96% at 14% 35%, rgba(255, 192, 121, 0.96) 0%, rgba(240, 123, 49, 0.95) 38%, rgba(197, 65, 27, 0.96) 72%, rgba(142, 35, 16, 0.98) 100%);
            border-radius: 44% 56% 48% 52% / 42% 54% 46% 58%;
            box-shadow: 0 8px 18px rgba(109, 27, 10, 0.38), inset 0 2px 4px rgba(255, 220, 182, 0.35), inset 0 -1px 3px rgba(120, 34, 16, 0.35);
            animation: kuahBlob 3.2s ease-in-out infinite;
        }

        .hero-accent-kuah::after {
            content: '';
            position: absolute;
            z-index: -1;
            left: 16%;
            right: 20%;
            top: 46%;
            height: 42%;
            border-radius: 999px;
            background: linear-gradient(105deg, rgba(255, 239, 211, 0.42) 0%, rgba(255, 239, 211, 0.08) 55%, rgba(255, 239, 211, 0) 100%);
            filter: blur(0.4px);
            animation: kuahShine 2.6s ease-in-out infinite;
            pointer-events: none;
        }

        @keyframes kuahBlob {
            0%, 100% {
                transform: translateY(-50%) rotate(-1.5deg) scale(1);
            }
            50% {
                transform: translateY(-50%) rotate(-0.4deg) scale(1.03, 0.98);
            }
        }

        @keyframes kuahShine {
            0%, 100% {
                opacity: 0.62;
                transform: translateX(0);
            }
            50% {
                opacity: 0.9;
                transform: translateX(3%);
            }
        }

        @keyframes caretBlink {
            0%, 50% {
                border-right-color: rgba(255, 255, 255, 0.95);
            }
            51%, 100% {
                border-right-color: transparent;
            }
        }
        
        /* Animasi Scroll Horizontal */
        @keyframes scrollX {
            0% {
                transform: translateX(0);
            }
            100% {
                transform: translateX(-50%);
            }
        }
        
        .animate-scroll-x {
            animation: scrollX 20s linear infinite;
        }
        
        .animate-scroll-x:hover {
            animation-play-state: paused;
        }

        .package-trust-chip {
            color: #5a1f18;
            padding: 0.22rem 0.1rem;
            font-size: 0.78rem;
            font-weight: 600;
            display: inline-flex;
            align-items: center;
            gap: 0.45rem;
        }

        .package-card {
            transition: transform 0.35s ease, opacity 0.25s ease, box-shadow 0.3s ease;
            will-change: transform;
        }

        .package-card:hover {
            transform: translateY(-5px);
        }

        .package-carousel {
            overflow-x: auto;
            overflow-y: hidden;
            scroll-behavior: smooth;
            scroll-snap-type: x mandatory;
            overscroll-behavior-x: contain;
            -ms-overflow-style: none;
            scrollbar-width: none;
            padding-bottom: 0.25rem;
            width: max-content;
            max-width: 100%;
            margin: 0 auto;
        }

        .package-carousel::-webkit-scrollbar {
            display: none;
        }

        .package-track {
            display: flex;
            align-items: stretch;
            gap: 1rem;
            padding-right: 0.25rem;
            width: max-content;
        }

        .package-slide {
            flex: 0 0 280px;
            scroll-snap-align: start;
            scroll-snap-stop: always;
        }

        .package-nav-btn {
            width: 38px;
            height: 38px;
            border-radius: 999px;
            border: 1px solid rgba(90, 31, 24, 0.15);
            background: rgba(255, 255, 255, 0.78);
            color: #5a1f18;
            display: inline-flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s ease;
        }

        .package-nav-btn:hover {
            background: #ffffff;
            transform: translateY(-1px);
        }

        .package-nav-btn:disabled {
            opacity: 0.45;
            cursor: not-allowed;
            transform: none;
        }

        @media (min-width: 640px) {
            .package-nav-btn {
                width: 40px;
                height: 40px;
            }

            .package-slide {
                flex-basis: 295px;
            }
        }

        @media (min-width: 1024px) {
            .package-slide {
                flex-basis: 310px;
            }
        }
    </style>
    <style>
        .fade-left {
            opacity: 1;
            transform: translateX(0);
            transition: opacity 0.6s ease, transform 0.6s ease;
        }
        .js .fade-left {
            opacity: 0;
            transform: translateX(-24px);
        }
        .fade-left.visible {
            opacity: 1;
