    <script>
        // Filter Menu
        document.querySelectorAll('.filter-btn').forEach(button => {
            button.addEventListener('click', function() {
                const filter = this.dataset.filter;
                
                // Update active button
                document.querySelectorAll('.filter-btn').forEach(btn => {
                    btn.classList.remove('active', 'bg-red-600', 'text-white');
                    btn.classList.add('bg-gray-300', 'text-gray-700');
                });
                this.classList.add('active', 'bg-red-600', 'text-white');
                
                // Show loading state
                const menuContainer = document.getElementById('menuContainer');
                menuContainer.innerHTML = '<div class="col-span-full text-center py-8"><i class="fas fa-spinner fa-spin text-3xl text-red-600"></i><p class="mt-4 text-gray-600">Memuat menu...</p></div>';
                
                // Ajax filter
                fetch(`/filter-menu?category=${filter}`)
                    .then(response => response.json())
                    .then(data => {
                        menuContainer.innerHTML = data.html;
                        
                        // Add fade-in animation to new items
                        const items = menuContainer.querySelectorAll('.menu-item');
                        items.forEach((item, index) => {
                            item.style.opacity = '0';
                            item.style.transform = 'translateY(20px)';
                            setTimeout(() => {
                                item.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
                                item.style.opacity = '1';
                                item.style.transform = 'translateY(0)';
                            }, index * 100);
                        });
                    })
                    .catch(error => {
                        console.error('Error:', error);
                        menuContainer.innerHTML = '<div class="col-span-full text-center py-8 text-red-600"><i class="fas fa-exclamation-triangle text-3xl"></i><p class="mt-4">Terjadi kesalahan saat memuat menu</p></div>';
                    });
            });
        });

        // ========== FUNGSI PAKET ==========
        function pilihPaket(paketType) {
            // Redirect to package detail page
            window.location.href = `/paket/${paketType.toLowerCase()}`;
        }

        function bukaModalOrder() {
            const modal = document.getElementById('modalOrder');
            if (!modal) return;
            modal.classList.remove('hidden');
            modal.classList.add('flex');
        }

        function tutupModalOrder() {
            const modal = document.getElementById('modalOrder');
            if (!modal) return;
            modal.classList.add('hidden');
            modal.classList.remove('flex');
        }

        function showLoginModal() {
            window.location.href = '{{ route('user.login') }}';
        }

        let packageName = '';
        const orderData = { nama: '' };

        function addPaketToCart(paketId) {
            @auth
            const token = document.querySelector('meta[name="csrf-token"]')?.getAttribute('content');
            fetch('{{ route('cart.add') }}', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'X-CSRF-TOKEN': token,
                    'Accept': 'application/json'
                },
                body: JSON.stringify({
                    type: 'paket',
                    id: paketId,
                    quantity: 1,
                })
            })
                .then(async (res) => {
                    if (!res.ok) {
                        throw new Error('Gagal menambahkan ke keranjang');
                    }
                    return await res.json();
                })
                .then(() => {
                    updateCartCount();
                    showNotification('Berhasil ditambahkan ke keranjang!', 'success');
                })
                .catch(() => {
                    showNotification('Gagal menambahkan ke keranjang', 'error');
                });
            @else
            showLoginModal();
            @endauth
        }

        function addToCartFromPackage(paketName) {
            packageName = paketName;
            orderData.nama = paketName;

            @auth
            bukaModalOrder();
            @else
            showLoginModal();
            @endauth
        }

        function addToCartByName(itemName) {
            console.log('addToCartByName:', itemName);
        }

        // ========== FUNGSI KERANJANG ==========
        function addToCart(menuItemId) {
            console.log('addToCart called with menuItemId:', menuItemId);
            
            // Check if user is authenticated
            @auth
            console.log('User is authenticated');
            // User is authenticated, proceed to add to cart
            @else
            console.log('User is not authenticated, showing login modal');
            // User is not authenticated, show login modal
            showLoginModal();
            return;
            @endauth
            
            // Open modal for authenticated users
            console.log('Opening add to cart modal');
            document.getElementById('modalMenuItemId').value = menuItemId;
            document.getElementById('addToCartModal').classList.remove('hidden');
            document.getElementById('modalQuantity').value = 1;
            document.getElementById('modalNotes').value = '';
            
            // Focus input for better UX
            setTimeout(() => {
                document.getElementById('modalQuantity')?.focus();
            }, 100);
        }

        function showAddToCartModal(menuItemId) {
            document.getElementById('modalMenuItemId').value = menuItemId;
            document.getElementById('modalQuantity').value = 1;
            document.getElementById('modalNotes').value = '';
            document.getElementById('addToCartModal').classList.remove('hidden');
            // Focus input for better UX
            setTimeout(() => {
                document.getElementById('modalQuantity')?.focus();
            }, 100);
        }

        function closeAddToCartModal() {
            document.getElementById('addToCartModal').classList.add('hidden');
            document.getElementById('addToCartForm').reset();
        }

        function showNotification(message, type = 'success') {
            // Buat elemen notifikasi
            const notification = document.createElement('div');
            notification.className = `fixed bottom-4 right-4 ${type === 'success' ? 'bg-green-600' : 'bg-red-600'} text-white px-6 py-3 rounded-lg shadow-lg z-50 transform transition-all duration-300`;
            notification.innerHTML = `
                <div class="flex items-center">
                    <i class="fas ${type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle'} mr-2"></i>
                    <span>${message}</span>
                </div>
            `;
            
            document.body.appendChild(notification);
            
            // Hapus otomatis setelah 3 detik
            setTimeout(() => {
                notification.remove();
            }, 3000);
        }

        function changeBackground(index) {
            const bg1 = document.getElementById('bg1');
            const bg2 = document.getElementById('bg2');
            const dot1 = document.getElementById('dot1');
            const dot2 = document.getElementById('dot2');
            if (!bg1 || !bg2 || !dot1 || !dot2) return;

            if (index === 1) {
                bg1.classList.remove('opacity-0');
                bg1.classList.add('opacity-100');
                bg2.classList.remove('opacity-100');
                bg2.classList.add('opacity-0');
                dot1.classList.replace('bg-white/40', 'bg-white/80');
                dot2.classList.replace('bg-white/80', 'bg-white/40');
            } else {
                bg2.classList.remove('opacity-0');
                bg2.classList.add('opacity-100');
                bg1.classList.remove('opacity-100');
                bg1.classList.add('opacity-0');
                dot2.classList.replace('bg-white/40', 'bg-white/80');
                dot1.classList.replace('bg-white/80', 'bg-white/40');
            }
        }


        function initHeroTyping() {
            const typedEl = document.getElementById('typedHeroTitle');
            if (!typedEl || typedEl.dataset.typed === 'true') return;

            const fullText = typedEl.dataset.text || 'Bakso Bunderan Ciomas';
            const highlightWord = 'Ciomas';
            const highlightStart = fullText.indexOf(highlightWord);
            typedEl.dataset.typed = 'true';

            if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
                typedEl.textContent = fullText;
                return;
            }

            typedEl.classList.add('typing-caret');
            typedEl.textContent = '';

            let charIndex = 0;
            let deleting = false;

            const typeSpeed = 120;
            const deleteSpeed = 80;
            const holdAtEnd = 1700;
            const holdAtStart = 500;

            function renderTypedText(count) {
                if (highlightStart < 0) {
                    typedEl.textContent = fullText.slice(0, count);
                    return;
                }

                const before = fullText.slice(0, Math.min(count, highlightStart));
                const highlighted = count > highlightStart
                    ? fullText.slice(highlightStart, Math.min(count, fullText.length))
                    : '';

                typedEl.innerHTML = `${before}<span class="hero-accent-kuah">${highlighted}</span>`;
            }

            function loopTyping() {
                if (!deleting) {
                    charIndex += 1;
                    renderTypedText(charIndex);

                    if (charIndex >= fullText.length) {
                        deleting = true;
                        setTimeout(loopTyping, holdAtEnd);
                        return;
                    }

                    setTimeout(loopTyping, typeSpeed);
                    return;
                }

                charIndex -= 1;
                renderTypedText(charIndex);

                if (charIndex <= 0) {
                    deleting = false;
                    setTimeout(loopTyping, holdAtStart);
                    return;
                }

                setTimeout(loopTyping, deleteSpeed);
            }

            loopTyping();
        }

        function initPackageCarousel() {
            const carousel = document.getElementById('packageCarousel');
            const navControls = document.getElementById('packageNavControls');
            const prevBtn = document.getElementById('packagePrevBtn');
            const nextBtn = document.getElementById('packageNextBtn');
            const firstSlide = carousel?.querySelector('.package-slide');
            if (!carousel || !prevBtn || !nextBtn) return;

            function updateButtons() {
                const maxScroll = Math.max(0, carousel.scrollWidth - carousel.clientWidth);
                const hasOverflow = maxScroll > 2;
                if (!hasOverflow) {
                    prevBtn.disabled = true;
                    nextBtn.disabled = true;
                    return;
                }
                prevBtn.disabled = carousel.scrollLeft <= 2;
                nextBtn.disabled = carousel.scrollLeft >= maxScroll - 2;
            }

            function syncNavVisibility() {
                const isDesktop = window.matchMedia('(min-width: 1024px)').matches;
                const hasOverflow = (carousel.scrollWidth - carousel.clientWidth) > 2;

                if (navControls) {
                    // On mobile/tablet: always show controls. On desktop: show only if overflow.
                    navControls.classList.toggle('hidden', isDesktop && !hasOverflow);
                }

                updateButtons();
            }

            function scrollByAmount(direction) {
                const slideGap = 16;
                const slideWidth = firstSlide ? firstSlide.getBoundingClientRect().width : 280;
                const amount = slideWidth + slideGap;
                carousel.scrollBy({
                    left: direction * amount,
                    behavior: 'smooth'
                });
            }

            prevBtn.addEventListener('click', () => scrollByAmount(-1));
            nextBtn.addEventListener('click', () => scrollByAmount(1));
            carousel.addEventListener('scroll', updateButtons, { passive: true });
            window.addEventListener('resize', syncNavVisibility);
            window.addEventListener('load', syncNavVisibility);
            requestAnimationFrame(syncNavVisibility);
        }

        initHeroTyping();
        initPackageCarousel();

        function updateCartCount() {
            fetch('/api/cart-count')
                .then(response => response.json())
                .then(data => {
                    const cartCount = document.getElementById('cartCount');
                    if (cartCount) {
                        cartCount.textContent = data.count;
                    }
                });
        }

        function pesanKeGofood() {
            alert(`Pesan ${orderData.nama} via Gofood\n\nAnda akan diarahkan ke aplikasi Gofood untuk menyelesaikan pesanan.`);
            window.open('https://gofood.co.id', '_blank');
            tutupModalOrder();
        }

        function pesanKeShopee() {
            alert(`Pesan ${orderData.nama} via Shopeefood\n\nAnda akan diarahkan ke aplikasi Shopeefood untuk menyelesaikan pesanan.`);
            window.open('https://shopeefood.co.id', '_blank');
            tutupModalOrder();
        }

        function pesanDirect() {
            // Tambahkan semua item paket ke keranjang
            const packageItems = [
                {name: 'Bakso Urat Special', quantity: 10},
                {name: 'Mie Ayam Kampung', quantity: 5},
                {name: 'Es Teh Manis', quantity: 10},
                {name: 'Sambal & Kerupuk', quantity: 5},
                {name: 'Alat Makan Lengkap', quantity: 1}
            ];
            
            // Tambahkan setiap item ke keranjang
            packageItems.forEach(item => {
                for(let i = 0; i < item.quantity; i++) {
                    addToCartByName(item.name);
                }
            });
            
            // Tampilkan notifikasi
            console.log('Showing notification for:', packageName);
            showNotification(`Paket ${orderData.nama} berhasil ditambahkan ke keranjang!`, 'success');
            
            // Tutup modal
            tutupModalOrder();
        }

        // Tutup modal
        const modalOrderEl = document.getElementById('modalOrder');
        if (modalOrderEl) {
            modalOrderEl.addEventListener('click', function(e) {
                if (e.target === this) {
                    tutupModalOrder();
                }
            });
        }

        // ========== AUTO GESER REKOMENDASI (LOOP MULUS) ==========
        function initRecommendedAutoScroll() {
            const slider = document.getElementById('rekomendasiSlider');
            const track = document.getElementById('rekomendasiTrack');
            const prevBtn = document.getElementById('rekomPrev');
            const nextBtn = document.getElementById('rekomNext');
            if (!slider || !track || !prevBtn || !nextBtn) return;

            const baseItems = Array.from(track.querySelectorAll('.rekomendasi-item'));
            if (baseItems.length <= 1) return;

            if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
                return;
            }

            let position = 0;
            let loopWidth = 0;
            let stepWidth = 0;
            let rafId = null;
            const speed = 0.45;

            function clearClones() {
                track.querySelectorAll('[data-reko-clone="1"]').forEach(el => el.remove());
            }

            function rebuild() {
                clearClones();
                baseItems.forEach(item => {
                    const clone = item.cloneNode(true);
                    clone.setAttribute('data-reko-clone', '1');
                    track.appendChild(clone);
                });

                const first = track.querySelector('.rekomendasi-item');
                const gap = parseFloat(getComputedStyle(track).columnGap || getComputedStyle(track).gap || '16') || 16;
                stepWidth = first ? (first.getBoundingClientRect().width + gap) : 220;
                loopWidth = (stepWidth * baseItems.length);
                position = ((position % loopWidth) + loopWidth) % loopWidth;
                track.style.transform = `translateX(${-position}px)`;
            }

            function tick() {
                if (loopWidth <= 0) {
                    rafId = requestAnimationFrame(tick);
                    return;
                }

                position += speed;
                if (position >= loopWidth) {
                    position -= loopWidth;
                }

                track.style.transform = `translateX(${-position}px)`;
                rafId = requestAnimationFrame(tick);
            }

            prevBtn.addEventListener('click', () => {
                if (loopWidth <= 0) return;
                position -= stepWidth;
                if (position < 0) position += loopWidth;
                track.style.transform = `translateX(${-position}px)`;
            });

            nextBtn.addEventListener('click', () => {
                if (loopWidth <= 0) return;
                position += stepWidth;
                if (position >= loopWidth) position -= loopWidth;
                track.style.transform = `translateX(${-position}px)`;
            });

            window.addEventListener('resize', rebuild);

            rebuild();
            if (!rafId) rafId = requestAnimationFrame(tick);
        }

        initRecommendedAutoScroll();

        // ========== FADE UP ANIMATION ==========
        const revealEls = document.querySelectorAll('.fade-up, .fade-left, .fade-right');
        if (revealEls.length > 0) {
            if ('IntersectionObserver' in window) {
                const observerOptions = {
                    threshold: 0.12,
                    rootMargin: '0px 0px -60px 0px'
                };

                const observer = new IntersectionObserver((entries) => {
                    entries.forEach(entry => {
                        if (entry.isIntersecting) {
                            entry.target.classList.add('visible');
                            observer.unobserve(entry.target);
                        }
                    });
                }, observerOptions);

                revealEls.forEach(el => observer.observe(el));
            } else {
                revealEls.forEach(el => el.classList.add('visible'));
            }
        }

        // ========== PHOTO HOVER EFFECT ==========
        const imgs = document.querySelectorAll('img');
        imgs.forEach(img => {
            if (img.closest('header')) return;
            if (img.closest('footer')) return;
            if (img.classList.contains('no-photo-hover')) return;
            img.classList.add('photo-hover');
        });
    </script>
</body>
